+                        Some(true),
+                    ));
+                }
+
+                let message = err.to_string();
+                let code = match err {
+                    crate::error::Error::Validation(_) => HostCallErrorCode::InvalidRequest,
+                    _ => HostCallErrorCode::Io,
+                };
