+        .payload
+        .get("options")
+        .or_else(|| request.payload.get("opts"));
+    options
+        .and_then(Value::as_object)
+        .and_then(|map| map.get("stream"))
+        .and_then(Value::as_bool)
+        .unwrap_or(false)
+}
