+fn is_streaming_http_request(request: &HostcallRequest) -> bool {
+    matches!(request.kind, HostcallKind::Http)
+        && request
+            .payload
+            .get("stream")
+            .and_then(Value::as_bool)
+            .unwrap_or(false)
+}
